(() => {
  'use strict';
  const X=window.JESED_GUERRAS_CONTEXT;if(!X)return;const {C,D,BOOK_ID}=X;
  const specs={"jesed-place-kaendar":{"region":"Centro-sul de Jesed · terras Polar","location":"Cidade elevada junto ao trecho inferior do Rio Grande, perto do Mar de Arvessa e protegida pela Garganta de Kaendar.","population":{"label":"Entre 18 mil e 26 mil habitantes antes da guerra","estimateMin":18000,"estimateMax":26000,"basis":"Três anéis urbanos, cais, muralhas, Conselho, oficinas, mercados, depósitos e multidões descritas ao longo do livro."},"summary":"Capital da Dinastia Polar, erguida em três anéis sobre uma elevação junto ao Rio Grande. É ao mesmo tempo fortaleza, centro de distribuição, símbolo de estabilidade e máquina de desigualdade.","description":["Kaendar foi construída para parecer inevitável. Os três anéis sobem a partir do cais e das zonas de trabalho até as câmaras de governo, criando uma cidade em que a geografia repete a hierarquia social. Muralhas, portões, túneis antigos, depósitos e passagens internas permitem que a cidade resista, mas também escondem decisões, pessoas e crimes.","A proximidade do Rio Grande transforma Kaendar em ponto de cobrança, transporte, pesca e entrada de mercadorias. A Garganta de Kaendar limita a aproximação por terra, enquanto o Cais dos Zírrios permite que o rio seja usado como acesso comercial ou vulnerabilidade militar.","Para o povo comum, Kaendar representa pão previsível, proteção e orgulho Polar. Para os clãs vizinhos, representa controle de passagem, memória de punições e uma dinastia que costuma chamar estabilidade ao que outros chamam domínio."],"narrativeFunction":"Centro político do livro e lugar onde a guerra deixa de ser ameaça externa para se tornar ruptura dentro da própria Dinastia Polar.","architecture":"Cidade circular ou semicircular fortificada, dividida em três anéis ascendentes, com muralhas, torres, cais, câmaras profundas, túneis ancestrais e edifícios de pedra ligados por rampas e passagens controladas.","atmosphere":"Pedra aquecida pelo sol, cheiro de rio e sal, sinos de portão, mercados comprimidos nos anéis baixos e silêncio disciplinado nos anéis altos. Durante o cerco, fumaça, fogo e medo atravessam todas as divisões.","resources":["Trecho inferior do Rio Grande","Salinas e litoral próximos","Armazéns de grãos e reservas","Cais, impostos e comércio","Mão de obra dos três anéis"],"dangers":["Cerco pela garganta ou pelo cais","Dependência de rotas externas de alimento","Conflito entre os anéis","Túneis usados para ocultação e infiltração","Concentração excessiva de poder"],"culture":["Lealdade pública à Dinastia Polar","Registo, lei e ritual político","Orgulho pela estabilidade de Orionus","Separação social entre os anéis","Defesa da cidade como defesa da própria identidade"],"chapterScenes":[{"chapterId":"jesed-chapter-gs-01","relation":"ocorre","text":"Dois Vigias levam ao governo a notícia dos jovens Polar mortos. Kaelina, Alyra, Daryon e Cal Edran transformam a descoberta numa crise de sucessão, honra e guerra.","characterIds":["jesed-character-kaelina-polar","jesed-character-alyra-polar","jesed-character-daryon-vess","jesed-character-cal-edran-polar"]},{"chapterId":"jesed-chapter-gs-02","relation":"ocorre","text":"Kaelina recupera a Lei do Portão e decide receber os Tondrar sob regras públicas, enquanto Alyra exige uma resposta de força.","characterIds":["jesed-character-kaelina-polar","jesed-character-alyra-polar","jesed-character-cal-edran-polar","jesed-character-daryon-vess"]},{"chapterId":"jesed-chapter-gs-04","relation":"ocorre","text":"A Câmara dos Onze debate guerra e negociação. A votação expõe as divisões do Conselho e a dificuldade de as gêmeas governarem como uma só autoridade.","characterIds":["jesed-character-kaelina-polar","jesed-character-alyra-polar","jesed-character-daryon-vess","jesed-character-cal-edran-polar","jesed-character-iressa-mao-de-sal","jesed-character-brokan-das-forjas","jesed-character-varron-meio-olho","jesed-character-nalia-do-rio","jesed-character-thoren-dos-graos","jesed-character-odran-porta-baixa","jesed-character-maelis-das-contagens","jesed-character-lurok","jesed-character-seron-das-obras"]},{"chapterId":"jesed-chapter-gs-05","relation":"ocorre","text":"Alyra rouba o talismã da caixa de provas e deixa Kaendar para contratar os Homens das Areias, escondendo da irmã que já decidiu fabricar uma retaliação.","characterIds":["jesed-character-alyra-polar","jesed-character-daryon-vess","jesed-character-iressa-mao-de-sal"]},{"chapterId":"jesed-chapter-gs-08","relation":"ocorre","text":"Kaelina atravessa os anéis baixos, visita a tumba de Orionus e é atacada nos túneis; Markoso intervém e mata o agressor.","characterIds":["jesed-character-kaelina-polar","jesed-character-orionus-polar","jesed-character-markoso"]},{"chapterId":"jesed-chapter-gs-10","relation":"ocorre","text":"Kaelina confronta Alyra pela humilhação de Cal Kadrir e recebe de Markoso a primeira pista material de que a versão oficial da guerra é falsa.","characterIds":["jesed-character-kaelina-polar","jesed-character-alyra-polar","jesed-character-cal-kadrir","jesed-character-markoso"]},{"chapterId":"jesed-chapter-gs-14","relation":"ocorre","text":"A crise de água e comida atinge os anéis. Kaelina acusa Alyra diante do Conselho e, à noite, segue Daryon até uma negociação secreta com Sarkan.","characterIds":["jesed-character-kaelina-polar","jesed-character-alyra-polar","jesed-character-daryon-vess","jesed-character-sarkan-boca-partida"]},{"chapterId":"jesed-chapter-gs-17","relation":"ocorre","text":"Kaelina reúne as pistas com Markoso, enquanto Alyra recebe provocações e sinais de que a guerra deixou de obedecer às suas ordens.","characterIds":["jesed-character-kaelina-polar","jesed-character-alyra-polar","jesed-character-markoso"]},{"chapterId":"jesed-chapter-gs-23","relation":"ocorre","text":"Com Kaendar cercada, Alyra leva o Conselho à Câmara do Primeiro Abrigo. Ali revela a gravidez a Daryon e escuta a confissão sobre o envenenamento de Yvenn.","characterIds":["jesed-character-alyra-polar","jesed-character-daryon-vess","jesed-character-cal-kadrir","jesed-character-iressa-mao-de-sal","jesed-character-lurok"]},{"chapterId":"jesed-chapter-gs-24","relation":"ocorre","text":"Rendar usa Kaelina como refém para abrir o cais. A aliança invade, Kaelina escapa com Markoso e vê Daryon encontrar Ylvena numa câmara secreta.","characterIds":["jesed-character-kaelina-polar","jesed-character-rendar","jesed-character-markoso","jesed-character-daryon-vess","jesed-character-ylvena"]},{"chapterId":"jesed-chapter-gs-25","relation":"ocorre","text":"Kaelina ouve a confissão de Ylvena e descobre a verdade sobre Orionus, os jovens Polar, Yvenn e Velarim. O confronto termina com a morte de Ylvena.","characterIds":["jesed-character-kaelina-polar","jesed-character-markoso","jesed-character-daryon-vess","jesed-character-ylvena"]},{"chapterId":"jesed-chapter-gs-26","relation":"ocorre","text":"Alyra deixa o abrigo, veste armadura e enfrenta Tavra numa torre. Iressa interfere e Tavra cai depois de perder o mecanismo de fogo.","characterIds":["jesed-character-alyra-polar","jesed-character-tavra-vendrar","jesed-character-iressa-mao-de-sal","jesed-character-rendar"]},{"chapterId":"jesed-chapter-gs-27","relation":"ocorre","text":"Kaelina fala diante dos exércitos, divide a aliança e regressa à cidade. No salão, Rendar força Daryon a confessar os crimes que construíram a guerra.","characterIds":["jesed-character-kaelina-polar","jesed-character-nynestra-buldar","jesed-character-kharvok","jesed-character-sarkan-boca-partida","jesed-character-rendar","jesed-character-alyra-polar","jesed-character-daryon-vess"]},{"chapterId":"jesed-chapter-gs-28","relation":"ocorre","text":"Kaelina concede passagem a Rendar, mas Alyra o mata pelas costas. As irmãs duelam e o mecanismo de Tavra explode, mutilando Alyra.","characterIds":["jesed-character-kaelina-polar","jesed-character-alyra-polar","jesed-character-rendar","jesed-character-daryon-vess"]},{"chapterId":"jesed-chapter-gs-29","relation":"ocorre","text":"O Conselho vota pela execução de Alyra. Kaelina realiza um golpe, impõe o exílio, cria o Registo do Portão e inicia vinte ciclos de governo único.","characterIds":["jesed-character-kaelina-polar","jesed-character-alyra-polar","jesed-character-iressa-mao-de-sal","jesed-character-lurok","jesed-character-markoso","jesed-character-sarkan-boca-partida"]}]},"jesed-place-khar-tondr":{"region":"Sudeste de Jesed · terras Tondrar","location":"Cidade-fortaleza encaixada entre as Montanhas de Karvoss e a entrada da Garganta Seca.","population":{"label":"Entre 7 mil e 11 mil habitantes","estimateMin":7000,"estimateMax":11000,"basis":"Fortaleza principal de um dos maiores clãs militares, com túneis, arena, bairros de barro e população reunida em cerimônias públicas."},"summary":"Fortaleza Tondrar de barro endurecido, pedra seca, túneis e pátios de tambor, construída para transformar escassez de água, espera e relevo em defesa.","description":["Khar-Tondr não se ergue acima da montanha; parece ter sido comprimida dentro dela. As construções baixas, os muros espessos e os acessos estreitos reduzem o efeito do calor e obrigam qualquer visitante a entrar sob observação.","A cidade é organizada por pátios de reunião, corredores de barro, depósitos de água, túneis e espaços onde pintura corporal, tambor e testemunho público possuem função política. A Plataforma do Sol Alto converte disputas de liderança em espetáculo coletivo.","A escassez molda a cultura local. Água, resistência, memória de ofensas e capacidade de suportar desconforto são tratados como medidas de caráter."],"narrativeFunction":"Mostra a guerra pelo olhar Tondrar e transforma Kaelina de soberana protegida em prisioneira obrigada a negociar com um povo que sua dinastia feriu.","architecture":"Construções baixas de barro e pedra, corredores estreitos, cisternas, túneis escavados, pátios de tambor e acessos controlados pela Garganta Seca.","atmosphere":"Calor seco durante o dia, frio mineral nos túneis, poeira vermelha, batidas de tambor e multidões que observam decisões como parte da justiça.","resources":["Cisternas e reservas controladas","Barro, pedra e pigmentos","Caça de montanha","Passagens defensáveis","Mão de obra treinada para cerco"],"dangers":["Sede","Deslizamentos e túneis estreitos","Conflitos de honra públicos","Gargantas fáceis de bloquear","Autoridade concentrada em líderes guerreiros"],"culture":["Pintura corporal como identidade","Tambores como comunicação e rito","Resistência física valorizada","Memória coletiva de pactos e humilhações","Justiça exposta diante do povo"],"chapterScenes":[{"chapterId":"jesed-chapter-gs-03","relation":"ocorre","text":"Rendar atravessa o território Tondrar e o leitor conhece a vigilância, os tambores e a lógica de Khar-Tondr.","characterIds":["jesed-character-rendar","jesed-character-kharvok","jesed-character-torgun-ossos-de-fome"]},{"chapterId":"jesed-chapter-gs-06","relation":"ocorre","text":"A comitiva Tondrar parte para o Marco das Três Pedras carregando pão, sal e a expectativa de que a Lei do Portão limite os Polar.","characterIds":["jesed-character-kharvok","jesed-character-yvenn-raiz-branca"]},{"chapterId":"jesed-chapter-gs-11","relation":"ocorre","text":"Rendar, Nynestra, Kharvok e os Vendrar negociam armas, alianças e custos enquanto a fortaleza se prepara para uma guerra maior.","characterIds":["jesed-character-rendar","jesed-character-nynestra-buldar","jesed-character-kharvok","jesed-character-torgun-ossos-de-fome","jesed-character-vorlan-vendrar","jesed-character-tavra-vendrar"]},{"chapterId":"jesed-chapter-gs-19","relation":"ocorre","text":"Kaelina chega prisioneira, é exposta na Plataforma do Sol Alto e levada às Veias de Barro.","characterIds":["jesed-character-kaelina-polar","jesed-character-nynestra-buldar","jesed-character-kharvok","jesed-character-torgun-ossos-de-fome"]},{"chapterId":"jesed-chapter-gs-21","relation":"ocorre","text":"Kaelina e Nynestra lutam diante do povo; o resultado impede uma execução imediata e altera a posição política da prisioneira.","characterIds":["jesed-character-kaelina-polar","jesed-character-nynestra-buldar","jesed-character-kharvok","jesed-character-torgun-ossos-de-fome"]}]},"jesed-place-nyn-harad":{"region":"Centro-leste de Jesed · Terra Preta","location":"Centro Buldar cercado por campos, canais, currais e rotas de grãos.","population":{"label":"Entre 9 mil e 14 mil habitantes","estimateMin":9000,"estimateMax":14000,"basis":"Principal centro de um clã territorialmente extenso, cercado por produção agrícola, celeiros, pátios e trabalhadores sazonais."},"summary":"Centro político e agrícola Buldar, baixo e largo, onde celeiros, canais, balanças e pátios valem mais do que torres.","description":["Nyn-Harad cresce horizontalmente sobre a Terra Preta. Casas de terra, celeiros, currais e pátios de pesagem formam um centro que existe para administrar colheita, água e trabalho.","O poder Buldar aparece menos em muralhas e mais em capacidade de alimentar ou deixar de alimentar os outros. Registros de grão, medidas, canais e rotas fazem parte da administração tanto quanto guerreiros.","A cidade recebe caravanas e representantes de áreas agrícolas distantes, o que a torna cheia em épocas de colheita e tensa quando a guerra ameaça as estradas."],"narrativeFunction":"Representa o poder logístico da guerra e o conflito de Nynestra entre proteger seu povo, vingar antigas perdas e não transformar alimento em instrumento de destruição.","architecture":"Construções baixas de terra e madeira, grandes celeiros, pátios de pesagem, canais de irrigação, currais e depósitos protegidos por cercas e guardas.","atmosphere":"Cheiro de terra úmida, grão seco e animais; movimento de carroças, contagens em voz alta e tensão constante quando as rotas fecham.","resources":["Terra fértil","Grãos e sementes","Rebanhos","Canais de irrigação","Carroças e trabalhadores agrícolas"],"dangers":["Incêndio de celeiros","Bloqueio das rotas de grão","Seca ou contaminação dos canais","Uso político da fome","Ataques durante a colheita"],"culture":["Prestígio ligado à produção e à partilha","Contagens e medidas públicas","Liderança prática","Rituais agrícolas","Memória de terras tomadas pelos Tondrar"],"chapterScenes":[{"chapterId":"jesed-chapter-gs-09","relation":"ocorre","text":"Nynestra organiza o poder Buldar e avalia o pedido de guerra a partir do custo que cairá sobre campos e famílias.","characterIds":["jesed-character-nynestra-buldar","jesed-character-orven"]},{"chapterId":"jesed-chapter-gs-12","relation":"ocorre","text":"Mensagens sobre Alesteiro e os movimentos dos clãs chegam às lideranças Buldar, aumentando a pressão para escolher um lado.","characterIds":["jesed-character-nynestra-buldar","jesed-character-orven"]},{"chapterId":"jesed-chapter-gs-16","relation":"ocorre","text":"Representantes e forças dos clãs reúnem-se nas terras Buldar, transformando grão, passagem e vingança em base para uma aliança.","characterIds":["jesed-character-nynestra-buldar","jesed-character-rendar","jesed-character-tavra-vendrar","jesed-character-torgun-ossos-de-fome","jesed-character-hadrun"]},{"chapterId":"jesed-chapter-gs-21","relation":"ocorre","text":"Notícias da luta em Khar-Tondr e do avanço da guerra obrigam Nynestra a equilibrar a aliança com a sobrevivência das terras férteis.","characterIds":["jesed-character-nynestra-buldar","jesed-character-hadrun"]},{"chapterId":"jesed-chapter-gs-22","relation":"ocorre","text":"A marcha parte das áreas Buldar em grupos separados, com provisões e rastros calculados para esconder o verdadeiro tamanho da aliança.","characterIds":["jesed-character-nynestra-buldar","jesed-character-rendar","jesed-character-hadrun"]}]},"jesed-place-velarim":{"region":"Entre as terras Buldar e Tondrar · Floresta de Mirval","location":"Aldeia escondida sob a cobertura da floresta, conhecida pelos demais clãs apenas como Aldeia Oculta.","population":{"label":"População atual: 0 · estimativa histórica entre 180 e 260 habitantes","estimateMin":0,"estimateMax":0,"historicalMin":180,"historicalMax":260,"basis":"Pequena comunidade familiar ocultada por trilhas falsas; destruída no massacre que antecede a guerra."},"summary":"Aldeia Fendelar escondida em Mirval, construída para desaparecer entre raízes, folhagem e trilhas falsas. Foi destruída para fabricar uma guerra.","description":["Velarim era pequena por necessidade. Casas de madeira escura, plataformas baixas e depósitos camuflados eram separados por vegetação para que uma única descoberta não revelasse toda a aldeia.","Os Fendelar evitavam estradas abertas, brasões e marcas permanentes. Crianças aprendiam rotas de fuga, sinais de caça e esconderijos antes de compreender a política dos clãs que os cercavam.","Depois do massacre, o lugar deixa de ser apenas ruína. Para Rendar, torna-se medida de toda decisão; para Kaendar, prova do que o poder Polar permitiu que fosse feito em seu nome."],"narrativeFunction":"Origem emocional da vingança de Rendar e principal custo humano da mentira construída por Alyra, Daryon e Ylvena.","architecture":"Casas dispersas e camufladas, passarelas baixas, depósitos sob raízes, abrigos infantis e acessos escondidos por vegetação e falsas trilhas.","atmosphere":"Antes do ataque, umidade, vozes baixas e sensação de abrigo secreto. Depois, madeira queimada, silêncio, restos cobertos pela floresta e memória de violência.","resources":["Caça e coleta de Mirval","Riachos ocultos","Madeira e fibras","Conhecimento de trilhas","Armadilhas e esconderijos"],"dangers":["Descoberta por outros clãs","Incêndio","Ataque concentrado a uma população pequena","Rhaukar e outros predadores de Mirval","Isolamento político"],"culture":["Vida familiar e comunitária discreta","Ausência de brasão","Conhecimento transmitido por rotas e histórias","Proteção das crianças","Desconfiança de autoridades externas"],"chapterScenes":[{"chapterId":"jesed-chapter-gs-03","relation":"ocorre","text":"O cotidiano de Rendar, Vita, Nara, Ilo e Avara mostra uma comunidade escondida que tenta viver fora das disputas dos grandes clãs.","characterIds":["jesed-character-rendar","jesed-character-vita-fendelar","jesed-character-avara-fendelar","jesed-character-nara","jesed-character-ilo"]},{"chapterId":"jesed-chapter-gs-07","relation":"ocorre","text":"Durante o ataque, crianças são levadas a esconderijos enquanto a aldeia é cercada e incendiada.","characterIds":["jesed-character-rendar","jesed-character-vita-fendelar","jesed-character-avara-fendelar","jesed-character-nara","jesed-character-ilo","jesed-character-veyr-polar"]},{"chapterId":"jesed-chapter-gs-10","relation":"ocorre","text":"Rendar retorna ao que restou de Velarim e transforma luto, culpa e sinais do massacre numa caçada contra os responsáveis.","characterIds":["jesed-character-rendar","jesed-character-veyr-polar"]},{"chapterId":"jesed-chapter-gs-13","relation":"citado","text":"As provas encontradas em Alesteiro e Kaendar reforçam que o massacre Fendelar não foi um ataque espontâneo, mas parte de uma operação maior.","characterIds":["jesed-character-kaelina-polar","jesed-character-rendar"]},{"chapterId":"jesed-chapter-gs-27","relation":"revelado","text":"Daryon confessa publicamente que escolheu Velarim como instrumento para construir a guerra e manipular Rendar.","characterIds":["jesed-character-daryon-vess","jesed-character-rendar"]}]},"jesed-place-margem-zirrios":{"region":"Norte de Jesed · terras Glydar","location":"Cidade ribeirinha no trecho alto do Rio Grande, abaixo das grandes quedas e próxima às rotas que descem para Kaendar.","population":{"label":"Entre 4 mil e 7 mil habitantes","estimateMin":4000,"estimateMax":7000,"basis":"Principal núcleo Glydar, com cais, pontes, pescadores, comércio fluvial e povoações ligadas."},"summary":"Principal cidade Glydar no alto Rio Grande, feita de cais, pontes, casas de madeira e plataformas ajustadas ao nível da água.","description":["A Margem dos Zírrios existe em função do rio. Casas de madeira, armazéns, pontes e cais acompanham o relevo irregular, e parte da cidade muda de uso conforme o nível da água.","Os Glydar dominam travessias, pesca, manutenção de barcos e leitura das cheias. A cidade é menos monumental que Kaendar, mas seu conhecimento do trecho alto do Rio Grande lhe dá poder que os Polar não conseguem substituir.","A ocupação e a batalha mostram como uma cidade construída para comércio pode transformar-se rapidamente em gargalo militar."],"narrativeFunction":"Amplia a guerra para o controle da água e demonstra que dominar uma cidade ribeirinha significa controlar movimento, alimento e comunicação.","architecture":"Casas de madeira sobre fundações altas, cais em vários níveis, pontes estreitas, plataformas de pesca, armazéns e torres de observação junto ao rio.","atmosphere":"Névoa, madeira molhada, ruído constante de água e cordas; durante a batalha, pontes tomadas, barcos queimados e civis presos entre margens.","resources":["Peixe e água doce","Barcos e remadores","Madeira húmida","Pedágios e comércio fluvial","Conhecimento das cheias"],"dangers":["Inundação","Incêndio nos cais","Bloqueio do rio","Ocupação por forças externas","Queda de pontes e correntezas"],"culture":["Identidade ligada ao rio","Prestígio de pescadores e barqueiros","Decisões práticas sobre cheia e travessia","Autonomia Glydar","Memória de ocupações"],"chapterScenes":[{"chapterId":"jesed-chapter-gs-15","relation":"ocorre","text":"A chegada de forças e emissários à região Glydar prepara o conflito pelo controle do rio.","characterIds":["jesed-character-rendar","jesed-character-nynestra-buldar","jesed-character-torgun-ossos-de-fome","jesed-character-ossar-glydar","jesed-character-kahul"]},{"chapterId":"jesed-chapter-gs-20","relation":"ocorre","text":"Rendar e seus aliados enfrentam a resistência Glydar, atravessam cais e pontes e transformam a Margem num campo de negociação e batalha.","characterIds":["jesed-character-rendar","jesed-character-nynestra-buldar","jesed-character-tavra-vendrar","jesed-character-ossar-glydar","jesed-character-varael-glydar","jesed-character-saela","jesed-character-lutharus"]},{"chapterId":"jesed-chapter-gs-22","relation":"ocorre","text":"A cidade ocupada torna-se ponto de passagem, abastecimento e tensão entre aliados que não possuem o mesmo objetivo para Kaendar.","characterIds":["jesed-character-rendar","jesed-character-nynestra-buldar","jesed-character-varael-glydar","jesed-character-hadrun"]},{"chapterId":"jesed-chapter-gs-23","relation":"ocorre","text":"Mensagens e forças saem da Margem enquanto a aliança fecha o cerco e calcula o uso do Rio Grande.","characterIds":["jesed-character-rendar","jesed-character-lutharus"]}]},"jesed-place-varkhama":{"region":"Nordeste de Jesed · terras Vendrar","location":"Assentamento de forjas aos pés do Monte Varkhama e da parte vulcânica das Montanhas de Karvoss.","population":{"label":"Entre 3 mil e 6 mil habitantes, com grande variação sazonal","estimateMin":3000,"estimateMax":6000,"basis":"Forja aberta, oficinas, túneis, mercadores, trabalhadores temporários e caravanas descritas no território Vendrar."},"summary":"Centro Vendrar de fogo, metal e comércio, mais parecido com um organismo de oficinas, tendas e depósitos do que com uma cidade planejada.","description":["Varkhama é barulhenta, improvisada e produtiva. Oficinas, barracas, depósitos, casas e túneis de extração crescem conforme novas oportunidades aparecem, sem formar ruas regulares.","O calor subterrâneo e o metal definem o lugar. Os Vendrar vendem ferramentas, armas, mecanismos e conhecimento técnico, mas a mesma capacidade que sustenta comércio torna o assentamento alvo de espionagem e pressão militar.","Mercadores, ferreiros, caçadores e combatentes convivem num espaço em que quase tudo possui preço e pouca coisa permanece secreta por muito tempo."],"narrativeFunction":"Introduz a tecnologia Vendrar e mostra como invenção, comércio e vingança podem tornar-se armas políticas.","architecture":"Oficinas abertas, forjas de pedra, tendas reforçadas, depósitos, passarelas, túneis de mineração e construções improvisadas ao redor de fontes de calor.","atmosphere":"Calor seco, cinza, ruído de martelos, cheiro de metal e multidões em movimento. À noite, as forjas mantêm o horizonte iluminado.","resources":["Minérios e metal trabalhado","Calor vulcânico","Ferramentas e armas","Mecanismos Vendrar","Comércio com vários clãs"],"dangers":["Fogo e explosões","Gases e túneis instáveis","Disputa por tecnologia","Mercenários","Dependência de rotas de alimento"],"culture":["Prestígio ligado ao ofício","Negociação direta","Competição entre oficinas","Tolerância a estrangeiros úteis","Tecnologia tratada como vantagem de clã"],"chapterScenes":[{"chapterId":"jesed-chapter-gs-11","relation":"ocorre","text":"Rendar e seus aliados negociam com Vorlan e Tavra. As forjas e os mecanismos Vendrar entram diretamente no conflito.","characterIds":["jesed-character-rendar","jesed-character-vorlan-vendrar","jesed-character-tavra-vendrar","jesed-character-nynestra-buldar"]},{"chapterId":"jesed-chapter-gs-16","relation":"ocorre","text":"Tavra e os Vendrar decidem quanto de sua tecnologia e de seus combatentes será colocado a serviço da aliança.","characterIds":["jesed-character-tavra-vendrar","jesed-character-nynestra-buldar","jesed-character-rendar","jesed-character-hadrun"]},{"chapterId":"jesed-chapter-gs-19","relation":"citado","text":"Preparativos e deslocamentos ligados ao mecanismo de fogo mostram que a guerra já alcançou as oficinas de Varkhama.","characterIds":["jesed-character-tavra-vendrar","jesed-character-hadrun"]}]},"jesed-place-cendar-vel":{"region":"Noroeste de Jesed · terras Cendar","location":"Povoação principal a oeste do Rio Grande, entre campos, bosques e zonas húmidas.","population":{"label":"Entre 4 mil e 7 mil habitantes","estimateMin":4000,"estimateMax":7000,"basis":"Centro de um clã médio com oficinas, campos de teste, armazéns, torres e produção alimentar própria."},"summary":"Centro Cendar de oficinas, madeira, rodas e mecanismos manuais, cercado por campos e zonas húmidas que garantem relativa autonomia alimentar.","description":["Cendar-Vel combina povoação, oficina e campo de teste. Casas de madeira e pedra dividem espaço com pórticos, roldanas, armazéns de peças e pequenas torres de observação.","Os Cendar constroem soluções com força humana, água, peso, encaixe e madeira flexível. Não são uma sociedade industrial, mas transformam problemas locais em mecanismos que outros clãs compram ou tentam copiar.","A proximidade dos pântanos e da fronteira Urtistar faz da cidade um centro inventivo e defensivo, sempre atento a materiais, passagem e cobrança."],"narrativeFunction":"Amplia a diversidade política de Jesed e estabelece uma fonte de engenharia prática que existe à margem do conflito principal.","architecture":"Casas de madeira e pedra, oficinas anexas, pórticos de teste, roldanas, guindastes manuais, pequenos canais e torres baixas.","atmosphere":"Madeira cortada, cordas tensionadas, água de pântano e ruído de mecanismos simples; cidade ativa, competitiva e desconfiada da fronteira.","resources":["Madeira flexível","Fibras e cipós","Campos e caça","Peças Vendrar adquiridas por comércio","Conhecimento de mecanismos manuais"],"dangers":["Incêndios de oficina","Pântanos","Conflitos com Urtistar","Falhas de mecanismos","Bloqueio das rotas ao Rio Grande"],"culture":["Orgulho inventivo","Competição entre oficinas","Autonomia alimentar","Aprendizado por tentativa","Defesa de fronteira"],"chapterScenes":[]},"jesed-place-urtar-vesh":{"region":"Oeste de Jesed · borda do Deserto de Veshkar","location":"Cidade-fortaleza entre floresta árida, poços e rotas de mercenários.","population":{"label":"Entre 3 mil e 5 mil habitantes","estimateMin":3000,"estimateMax":5000,"basis":"Cidade fixa de um clã médio, com fortificação, currais, poços, pátios de lâmina e combatentes por contrato."},"summary":"Fortaleza Urtistar de pedra seca e madeira escura, construída para proteger poços, currais e rotas de lâmina na borda do deserto.","description":["Urtar-Vesh não é um acampamento nômade. É uma cidade compacta, cercada por pedra seca, pátios de treino e depósitos de água, onde grupos armados partem para contratos e regressam com pagamento, feridos ou novos inimigos.","A vida depende dos Poços de Ardel, da caça no bosque seco e do controle das rotas que evitam as partes mais hostis do deserto.","A cultura de contrato oferece previsibilidade num território duro: uma palavra aceita precisa ter limite, preço e consequência."],"narrativeFunction":"Dá origem a uma força externa capaz de alterar o equilíbrio do cerco e mostra uma sociedade guerreira que não se reduz ao caos ou à lealdade gratuita.","architecture":"Muralhas baixas de pedra seca, portões estreitos, pátios de lâmina, currais, depósitos e casas de madeira escura protegidas do vento do deserto.","atmosphere":"Ar seco, poeira, metal raspado, animais inquietos e negociações feitas em voz baixa antes de partidas armadas.","resources":["Poços e reservas de água","Caça de floresta árida","Animais de carga","Combatentes por contrato","Passagem para o oeste"],"dangers":["Seca","Ataques a poços","Conflitos de fronteira com Cendar","Tempestades de areia","Contratos que arrastam a cidade para guerras distantes"],"culture":["Palavra contratual","Prestígio de combatentes e escoltas","Autonomia do clã","Treino de lâmina","Respeito por pagamento e consequência"],"chapterScenes":[]},"jesed-place-homens-areias":{"region":"Extremo oeste/sudoeste · limite do Deserto de Veshkar","location":"Acampamento móvel de exilados e mercenários fora do controle direto dos clãs.","population":{"label":"Entre 300 e 600 pessoas, variando com contratos e deslocamentos","estimateMin":300,"estimateMax":600,"basis":"Acampamento de exilados, famílias, combatentes e seguidores; a população aumenta ou diminui conforme contratos e perdas."},"summary":"Assentamento móvel dos Homens das Areias, formado por tendas, carroças, fogueiras baixas e pessoas expulsas de outros territórios.","description":["O acampamento muda de forma conforme a água, os contratos e a necessidade de desaparecer. Tendas baixas, carroças reaproveitadas e círculos de vigia substituem muralhas.","Os Homens das Areias reúnem exilados, mercenários, famílias e pessoas que já não encontram proteção nos clãs de origem. Essa mistura torna o grupo flexível, perigoso e impossível de resumir apenas como bandidos.","Sarkan usa a necessidade coletiva como poder de negociação. Quem paga compra força, mas nunca controla completamente o que essa força deseja depois do pagamento."],"narrativeFunction":"Mostra o custo social do exílio Polar e fornece a Alyra e Daryon uma força sem vínculo institucional para cometer crimes negáveis.","architecture":"Tendas baixas, carroças, cercas temporárias, fossos rasos, fogueiras protegidas e postos de vigia desmontáveis.","atmosphere":"Poeira, couro, fumaça baixa e silêncio de pessoas acostumadas a partir rapidamente.","resources":["Combatentes experientes","Animais e carroças","Rotas do deserto","Objetos reaproveitados","Informação trazida por exilados"],"dangers":["Falta de água","Tempestades de areia","Conflitos internos","Contratos traiçoeiros","Retaliação dos clãs"],"culture":["Identidade construída pelo exílio","Lealdade negociada","Proteção das próprias famílias","Desconfiança de autoridades","Pragmatismo de sobrevivência"],"chapterScenes":[{"chapterId":"jesed-chapter-gs-05","relation":"ocorre","text":"Alyra negocia secretamente com Sarkan o ataque a Velarim e entrega aos exilados uma guerra que poderá ser negada por Kaendar.","characterIds":["jesed-character-alyra-polar","jesed-character-sarkan-boca-partida","jesed-character-daryon-vess"]},{"chapterId":"jesed-chapter-gs-14","relation":"ocorre","text":"Kaelina segue Daryon e o encontra negociando com Sarkan, percebendo que os Homens das Areias estão ligados a decisões tomadas dentro de Kaendar.","characterIds":["jesed-character-kaelina-polar","jesed-character-daryon-vess","jesed-character-sarkan-boca-partida"]},{"chapterId":"jesed-chapter-gs-17","relation":"citado","text":"As consequências dos contratos e a mudança de lealdades mostram que Sarkan não pretende continuar sendo apenas instrumento dos Polar.","characterIds":["jesed-character-sarkan-boca-partida","jesed-character-kaelina-polar"]}]},"jesed-place-marco-tres-pedras":{"region":"Entre as terras Polar e Tondrar","location":"Terreno aberto escolhido por não pertencer plenamente a nenhum dos lados, marcado por três grandes pedras.","population":null,"summary":"Lugar de trégua onde pão, sal, água e testemunhas deveriam impedir a guerra, mas se tornam cenário de envenenamento e massacre.","description":["O Marco das Três Pedras é simples porque sua autoridade depende do costume, não de muralhas. As pedras delimitam o espaço, as comitivas mantêm distância e os alimentos partilhados tornam pública a intenção de negociar.","A neutralidade existe apenas enquanto todos aceitam a mesma leitura da lei. Quando Yvenn é envenenado, cada gesto que deveria produzir confiança passa a funcionar como prova de traição.","Depois do massacre, o lugar permanece como lembrança física de uma lei que não falhou sozinha: foi manipulada por pessoas que precisavam que ela parecesse inútil."],"narrativeFunction":"Transforma a tentativa de paz em início aberto da guerra e demonstra como uma regra pode ser destruída quando a prova é fabricada.","architecture":"Três monólitos, terreno limpo, espaço central para pão e sal e zonas opostas para as comitivas. Não possui construções permanentes.","atmosphere":"Vento aberto, silêncio cerimonial e distância calculada; depois, comida derrubada, sangue e corpos entre as pedras.","resources":["Posição intermediária","Visibilidade para testemunhas","Espaço para comitivas"],"dangers":["Emboscada","Veneno","Interpretação hostil de qualquer movimento","Ausência de abrigo"],"culture":["Símbolo da Lei do Portão","Partilha de pão, água e sal","Testemunho público","Neutralidade sustentada apenas por costume"],"chapterScenes":[{"chapterId":"jesed-chapter-gs-06","relation":"ocorre","text":"Kaelina e Alyra encontram Kharvok e Yvenn para aplicar a Lei do Portão. Yvenn é envenenado e a negociação termina num massacre entre Polar e Tondrar.","characterIds":["jesed-character-kaelina-polar","jesed-character-alyra-polar","jesed-character-daryon-vess","jesed-character-cal-edran-polar","jesed-character-kharvok","jesed-character-yvenn-raiz-branca","jesed-character-iressa-mao-de-sal","jesed-character-maelis-das-contagens"]}]},"jesed-place-alesteiro":{"region":"Terras Polar · rota oriental de depósitos","location":"Vila de abastecimento ligada a reservas, oficinas e passagem entre Kaendar e as fronteiras orientais.","population":{"label":"Após a devastação: estimada entre 200 e 450 pessoas · antes do ataque, entre 900 e 1.300","estimateMin":200,"estimateMax":450,"historicalMin":900,"historicalMax":1300,"basis":"Vila com depósitos e população suficiente para produzir vítimas, evacuação e resposta militar; destruída por fogo e explosões."},"summary":"Vila Polar de depósitos e passagem, devastada por fogo Vendrar. A morte de Cal Edran transforma o lugar em prova de que a guerra já não pode ser mantida fora de Kaendar.","description":["Alesteiro existia para receber, guardar e redistribuir materiais nas rotas orientais. Depósitos, pátios de carroça, casas de trabalhadores e pequenas oficinas formavam uma vila funcional, dependente da proteção de Kaendar.","O ataque converte as estruturas de armazenamento em combustível. Fogo e explosões atravessam a vila, obrigando moradores e soldados a escolher entre salvar pessoas, reservas ou rotas.","Quando Kaelina chega, encontra não apenas destruição, mas indícios que contradizem a explicação oficial e o corpo de Cal Edran, que permaneceu para garantir a retirada dos outros."],"narrativeFunction":"Leva a guerra ao território Polar, mata o principal escudo das gêmeas e oferece a Kaelina provas de que vários clãs estão sendo usados como versões convenientes da mesma mentira.","architecture":"Depósitos de madeira e pedra, pátios de carroça, casas baixas, oficinas e cercas de controle de carga.","atmosphere":"Antes, rotina de carregamento e poeira de estrada; depois, fumaça, metal queimado, depósitos abertos e sobreviventes procurando familiares.","resources":["Reservas e cargas","Carroças","Ferramentas","Ponto de descanso das rotas"],"dangers":["Incêndio em depósitos","Explosões","Ataques de fronteira","Isolamento em caso de bloqueio"],"culture":["Comunidade de trabalhadores e carregadores","Dependência da proteção Polar","Vida organizada pelo fluxo das caravanas"],"chapterScenes":[{"chapterId":"jesed-chapter-gs-12","relation":"ocorre","text":"Alyra insiste em ir a Alesteiro durante o ataque. Cal Edran a salva e permanece para conter o desastre enquanto a vila arde.","characterIds":["jesed-character-alyra-polar","jesed-character-cal-edran-polar","jesed-character-cal-kadrir"]},{"chapterId":"jesed-chapter-gs-13","relation":"ocorre","text":"Kaelina chega às ruínas, encontra Cal Edran morto e identifica um laço de técnica Fendelar, contrariando a versão de um ataque simples.","characterIds":["jesed-character-kaelina-polar","jesed-character-cal-edran-polar","jesed-character-soren","jesed-character-harrev","jesed-character-odris"]}]},"jesed-place-noreval":{"region":"Interior das terras Polar","location":"Povoação antiga fora dos anéis de Kaendar, ligada a famílias de serviço, arquivos locais e rotas menores.","population":{"label":"Entre 900 e 1.500 habitantes","estimateMin":900,"estimateMax":1500,"basis":"Povoação de origem de várias famílias, com arquivos, casas antigas e vida própria fora da capital."},"summary":"Povoação discreta ligada ao passado de Daryon, Ylvena e Savel, onde registros locais preservam o que os arquivos de Kaendar tentaram apagar.","description":["Noreval é uma comunidade antiga, de casas baixas, pátios familiares e registros mantidos por pessoas que se conhecem por gerações. A distância de Kaendar reduz prestígio, mas preserva memórias que a capital considera pequenas demais para controlar.","Daryon e Ylvena partem dali em busca de importância. Quando Kaelina regressa para investigar, a povoação revela lacunas, nomes alterados e uma relação anterior que não deveria ter desaparecido dos documentos oficiais.","O lugar mostra que poder também se constrói pela capacidade de abandonar uma origem e reescrever o caminho percorrido."],"narrativeFunction":"Fornece a Kaelina a primeira prova de que Daryon fabricou a própria história e manteve uma ligação antiga com Ylvena.","architecture":"Casas de pedra e madeira, pátios familiares, pequeno arquivo comunitário, depósitos modestos e caminhos estreitos entre propriedades.","atmosphere":"Ritmo lento, memória longa e desconfiança diante de visitantes da capital; documentos antigos cheiram a poeira e umidade.","resources":["Arquivos locais","Produção agrícola modesta","Conhecimento de famílias antigas","Rotas secundárias"],"dangers":["Pressão política de Kaendar","Desaparecimento ou alteração de registros","Isolamento"],"culture":["Memória familiar","Reputação construída por gerações","Pouca mobilidade social","Cuidado com documentos e testemunhos"],"chapterScenes":[{"chapterId":"jesed-chapter-gs-18","relation":"ocorre","text":"Kaelina chega com Harrev e Odris, consulta registros e escuta Savel. Descobre que Daryon e Ylvena vieram da mesma povoação e tiveram uma ligação apagada.","characterIds":["jesed-character-kaelina-polar","jesed-character-savel","jesed-character-daryon-vess","jesed-character-ylvena","jesed-character-harrev","jesed-character-odris"]}]},"jesed-place-nhar-veyr":{"region":"Fronteira entre terras Polar, Buldar e Tondrar","location":"Pequena vila de passagem em área de autoridade ambígua.","population":{"label":"Durante a armadilha: desabitada · estimativa anterior entre 120 e 220 habitantes","estimateMin":0,"estimateMax":0,"historicalMin":120,"historicalMax":220,"basis":"Vila pequena esvaziada para servir de armadilha, com casas e caminhos suficientes para ocultar atacantes."},"summary":"Vila de fronteira esvaziada e usada para atrair Kaelina a uma emboscada, onde a ausência de habitantes se torna parte do perigo.","description":["Nhar-Veyr foi construída para viajantes, lavradores e pequenas trocas entre territórios. Sua posição entre autoridades diferentes torna a vila útil em tempos de paz e vulnerável quando nenhum clã deseja assumir responsabilidade.","Na chegada de Kaelina, portas abertas, fogos apagados e ruas vazias indicam que a população foi retirada ou fugiu. A própria estrutura da vila é usada para canalizar os guardas e ocultar os atacantes.","O lugar deixa claro que, numa guerra de versões, uma vila pode desaparecer antes que alguém admita tê-la sacrificado."],"narrativeFunction":"Isola Kaelina, mata Harrev e Odris e permite que os Tondrar capturem a soberana sem atacar diretamente Kaendar.","architecture":"Casas simples de madeira e barro, pequeno pátio de troca, cercas agrícolas e caminhos que se abrem para várias fronteiras.","atmosphere":"Silêncio anormal, portas abandonadas, poeira sem passos e sensação de que cada janela observa.","resources":["Ponto de passagem","Pequenos campos","Água local","Abrigo para viajantes"],"dangers":["Emboscadas","Ausência de autoridade clara","Evacuação forçada","Ataques de fronteira"],"culture":["Comunidade de passagem","Mistura de costumes fronteiriços","Dependência de acordos entre clãs"],"chapterScenes":[{"chapterId":"jesed-chapter-gs-19","relation":"ocorre","text":"Kaelina, Harrev e Odris entram na vila vazia. A armadilha fecha, os dois guardas morrem e Kaelina é capturada.","characterIds":["jesed-character-kaelina-polar","jesed-character-harrev","jesed-character-odris","jesed-character-kharvok"]}]},"jesed-place-plataforma-sol-alto":{"region":"Khar-Tondr · terras Tondrar","location":"Arena pública circular no centro cerimonial da fortaleza.","population":null,"summary":"Plataforma de cerca de quatro metros de altura, cercada por vãos e anéis de lanças, onde o povo Tondrar observa julgamentos físicos e disputas de autoridade.","description":["A organização do espaço segue uma sequência deliberada: povo, anel de lanças, vão, plataforma central, novo vão, segundo anel e povo. A distância impede interferência fácil e transforma cada movimento em espetáculo.","A plataforma possui cerca de quatro metros de altura. Não é uma arena de entretenimento comum, mas um lugar em que força, resistência e decisão política são tornadas visíveis.","Quando Kaelina e Nynestra lutam, o espaço obriga ambas a representar papéis que não correspondem completamente ao plano secreto construído nas celas."],"narrativeFunction":"Converte a negociação entre Kaelina e Nynestra numa luta pública e permite que ambas alterem a política Tondrar sem revelar imediatamente a aliança entre elas.","architecture":"Plataforma circular elevada, com escadas controladas, vãos de separação e dois anéis concêntricos de lanças entre o centro e a multidão.","atmosphere":"Sol direto, poeira, metal, gritos e silêncio súbito quando uma decisão física passa a valer como argumento político.","resources":["Visibilidade pública","Controle da multidão","Símbolo de autoridade"],"dangers":["Queda da plataforma","Lanças dos anéis","Intervenção da multidão","Combate sem abrigo"],"culture":["Julgamento público","Resistência como prova","Participação coletiva pela observação","Autoridade confirmada diante do povo"],"chapterScenes":[{"chapterId":"jesed-chapter-gs-19","relation":"ocorre","text":"Kaelina é apresentada como prisioneira e entende que será usada numa demonstração pública de poder.","characterIds":["jesed-character-kaelina-polar","jesed-character-nynestra-buldar","jesed-character-kharvok","jesed-character-torgun-ossos-de-fome"]},{"chapterId":"jesed-chapter-gs-21","relation":"ocorre","text":"Kaelina e Nynestra lutam de verdade o suficiente para convencer o povo. Nynestra impede que a soberana seja executada e redefine o valor político da prisioneira.","characterIds":["jesed-character-kaelina-polar","jesed-character-nynestra-buldar","jesed-character-kharvok","jesed-character-torgun-ossos-de-fome"]}]},"jesed-place-veias-barro":{"region":"Subsolo de Khar-Tondr","location":"Rede de túneis, celas e corredores escavados sob a fortaleza Tondrar.","population":null,"summary":"Túneis frios de barro e pedra usados como prisão, passagem e reserva defensiva sob Khar-Tondr.","description":["As Veias de Barro seguem camadas naturais do terreno e foram ampliadas ao longo de gerações. Algumas partes servem como celas; outras ligam cisternas, depósitos e saídas de emergência.","A umidade e o frio contrastam com o calor da superfície. Marcas nas paredes indicam circulação, vigia e antigas ampliações, mas um visitante dificilmente compreende a rede completa.","É nas celas que Kaelina e Nynestra conseguem falar fora do olhar do povo e transformar uma luta anunciada em plano político."],"narrativeFunction":"Cria o espaço privado necessário para que inimigas aparentes negociem antes de representar conflito diante de Khar-Tondr.","architecture":"Corredores estreitos de barro endurecido, nichos, portas pesadas, celas, passagens inclinadas e ligações com cisternas.","atmosphere":"Frio, cheiro de terra húmida, pouca luz e sons que percorrem os corredores sem revelar a origem.","resources":["Água subterrânea","Abrigos defensivos","Passagens secretas","Celas e depósitos"],"dangers":["Desorientação","Desabamento","Falta de luz","Vigilância constante"],"culture":["Conhecimento das rotas restrito","Prisioneiros mantidos fora do sol","Uso do subsolo como extensão da defesa Tondrar"],"chapterScenes":[{"chapterId":"jesed-chapter-gs-19","relation":"ocorre","text":"Kaelina é presa nas celas e encontra Nynestra. As duas testam intenções e começam a construir um plano.","characterIds":["jesed-character-kaelina-polar","jesed-character-nynestra-buldar"]},{"chapterId":"jesed-chapter-gs-21","relation":"ocorre","text":"Antes da luta pública, Kaelina e Nynestra definem limites, riscos e o modo de transformar a arena numa saída política.","characterIds":["jesed-character-kaelina-polar","jesed-character-nynestra-buldar"]}]},"jesed-place-camara-primeiro-abrigo":{"region":"Subsolo profundo de Kaendar","location":"Câmara antiga abaixo dos anéis e dos túneis conhecidos pela maior parte da cidade.","population":null,"summary":"Abrigo mais profundo de Kaendar, preservado para crises extremas e usado por Alyra para proteger o Conselho durante o cerco.","description":["A Câmara do Primeiro Abrigo pertence à camada mais antiga de Kaendar. Paredes grossas, corredores estreitos e reservas de emergência mostram que foi feita para manter um pequeno núcleo vivo quando a cidade acima não pudesse ser defendida.","O espaço reduz soberanos, conselheiros e guardas à mesma falta de ar e à mesma incerteza. Sem janelas e sem notícia segura das muralhas, informação torna-se tão importante quanto comida.","Alyra usa a câmara como último centro de comando, mas a proximidade com Daryon também faz emergir a gravidez, a mentira sobre a paternidade e a confissão de que ele matou Yvenn."],"narrativeFunction":"Isola o governo de Kaendar no momento do cerco e concentra a ruptura íntima e política entre Alyra, Daryon e o Conselho.","architecture":"Pedra espessa, teto baixo, bancos, depósitos, portas reforçadas, corredores de acesso e ventilação limitada.","atmosphere":"Ar pesado, tochas, vozes contidas e sensação de que a cidade inteira pode desabar acima.","resources":["Reservas de emergência","Água armazenada","Proteção contra ataque direto","Acesso a túneis antigos"],"dangers":["Ficar preso","Falta de informação","Ventilação limitada","Controle do acesso por poucos guardas"],"culture":["Memória das primeiras crises de Kaendar","Prioridade de preservar liderança e registros","Uso apenas em risco extremo"],"chapterScenes":[{"chapterId":"jesed-chapter-gs-23","relation":"ocorre","text":"Alyra conduz o Conselho ao abrigo. Expulsa Lurok, revela a aliança Urtistar, testa Daryon sobre a gravidez e escuta que ele envenenou Yvenn.","characterIds":["jesed-character-alyra-polar","jesed-character-daryon-vess","jesed-character-cal-kadrir","jesed-character-iressa-mao-de-sal","jesed-character-lurok","jesed-character-brokan-das-forjas","jesed-character-varron-meio-olho","jesed-character-nalia-do-rio","jesed-character-thoren-dos-graos","jesed-character-odran-porta-baixa","jesed-character-maelis-das-contagens","jesed-character-seron-das-obras"]}]},"jesed-place-terra-preta":{"region":"Centro-leste de Jesed · terras Buldar","location":"Grande faixa fértil de campos, vales, canais e povoações ao redor de Nyn-Harad.","population":null,"summary":"Coração agrícola das terras Buldar, cuja fertilidade alimenta vários clãs e torna cada estrada, canal e celeiro parte da política de Jesed.","description":["A Terra Preta é uma região, não uma única cidade. O solo escuro, os vales suaves e os canais permitem colheitas mais regulares do que em quase qualquer outro território conhecido.","Povoações, campos e currais espalham-se ao redor de Nyn-Harad. A autoridade Buldar depende da capacidade de coordenar essa extensão sem destruir a autonomia de cada área produtora.","Durante a guerra, a região torna-se ponto de reunião, abastecimento e disputa. Quem atravessa a Terra Preta precisa de grão, carroças e permissão para não ser tratado como ameaça."],"narrativeFunction":"Materializa o poder do alimento e permite que a aliança contra Kaendar exista logisticamente.","architecture":"Paisagem de campos, canais, celeiros, pontes pequenas, cercas e povoações baixas.","atmosphere":"Terra úmida, vento sobre grãos, carroças e atividade sazonal; em tempo de guerra, fogueiras de acampamento e guardas nas estradas.","resources":["Grãos","Sementes","Pastagens","Água de irrigação","Carroças e animais de carga"],"dangers":["Seca","Incêndio de campos","Pragas","Exércitos consumindo reservas","Bloqueio da Estrada dos Grãos"],"culture":["Calendário agrícola","Partilha e armazenamento","Rituais de semente","Prestígio de produtores","Contagem pública de reservas"],"chapterScenes":[{"chapterId":"jesed-chapter-gs-09","relation":"ocorre","text":"Nynestra e Orven discutem a posição Buldar enquanto campos e reservas definem quanto tempo o clã pode sustentar uma guerra.","characterIds":["jesed-character-nynestra-buldar","jesed-character-orven"]},{"chapterId":"jesed-chapter-gs-16","relation":"ocorre","text":"Clãs e combatentes reúnem-se na região para negociar uma aliança, distribuir provisões e planejar movimentos contra Kaendar.","characterIds":["jesed-character-rendar","jesed-character-nynestra-buldar","jesed-character-torgun-ossos-de-fome","jesed-character-tavra-vendrar","jesed-character-hadrun"]}]},"jesed-place-floresta-mirval":{"region":"Entre Buldar e Tondrar","location":"Floresta pequena e densa ao sul das áreas Buldar e próxima das antigas rotas Tondrar.","population":null,"summary":"Floresta Fendelar de cobertura fechada, riachos, trilhas falsas e ruínas antigas, capaz de esconder uma comunidade inteira dos mapas dos grandes clãs.","description":["Mirval parece menor no mapa do que é para quem tenta atravessá-la. Vegetação fechada, zonas húmidas, riachos e mudanças de relevo quebram linhas de visão e tornam inúteis muitas formações militares.","Os Fendelar aprenderam a alterar trilhas, plantar falsos rastros e usar pontos de observação sem construir fortificações visíveis. A floresta era defesa, alimento e arquivo cultural.","Depois da destruição de Velarim, Mirval preserva restos, crianças escondidas, armadilhas e ruínas que outros povos não sabem interpretar."],"narrativeFunction":"Protege e depois testemunha a destruição dos Fendelar, além de ligar a guerra atual a camadas antigas da história de Jesed.","architecture":"Sem arquitetura única: trilhas alteradas, plataformas discretas, abrigos sob raízes, pontes pequenas e ruínas cobertas pela vegetação.","atmosphere":"Umidade, sombra, ruído de água e sensação de ser observado. A floresta muda de significado conforme quem conhece ou ignora suas trilhas.","resources":["Caça","Água de riachos","Madeira e fibras","Plantas medicinais","Ocultação natural"],"dangers":["Rhaukar","Armadilhas","Perda de orientação","Incêndio","Patrulhas e caçadores externos"],"culture":["Conhecimento de trilhas","Ausência de marcas permanentes","Proteção das crianças","Histórias transmitidas oralmente","Uso da floresta como fronteira viva"],"chapterScenes":[{"chapterId":"jesed-chapter-gs-03","relation":"ocorre","text":"Rendar caça e regressa a Velarim, revelando como os Fendelar se movem sem deixar trilhas claras.","characterIds":["jesed-character-rendar","jesed-character-vita-fendelar","jesed-character-avara-fendelar","jesed-character-nara","jesed-character-ilo"]},{"chapterId":"jesed-chapter-gs-07","relation":"ocorre","text":"O ataque atravessa Mirval. Crianças e sobreviventes usam esconderijos enquanto fogo e perseguidores rompem as defesas da floresta.","characterIds":["jesed-character-rendar","jesed-character-vita-fendelar","jesed-character-avara-fendelar","jesed-character-nara","jesed-character-ilo","jesed-character-veyr-polar"]},{"chapterId":"jesed-chapter-gs-10","relation":"ocorre","text":"Rendar percorre as ruínas e os rastros do massacre, procurando sinais de autoria e sobreviventes.","characterIds":["jesed-character-rendar","jesed-character-veyr-polar"]},{"chapterId":"jesed-chapter-gs-19","relation":"citado","text":"Movimentos entre as fronteiras de Mirval e Tondrar ajudam a ocultar capturas, patrulhas e deslocamentos da guerra.","characterIds":["jesed-character-kaelina-polar","jesed-character-kharvok"]}]},"route-rio-grande":{"region":"Eixo norte-sul de Jesed","location":"Nasce nas terras Glydar, atravessa o território Polar e deságua no Mar de Arvessa.","population":null,"summary":"Principal rota fluvial de Jesed, fonte de alimento, transporte, imposto e disputa entre quem controla as nascentes e quem controla a foz.","description":["O Rio Grande começa frio e violento nas terras Glydar, desce por quedas e curvas largas e torna-se navegável antes de alcançar Kaendar e o mar.","A parte alta depende do conhecimento Glydar; a parte baixa, do controle Polar. Nenhum dos dois clãs domina sozinho todo o sistema, embora ambos frequentemente se comportem como se dominassem.","Barcos, pesca, tributos e travessias fazem do rio uma rota. Em guerra, pontes, cais e margens tornam-se alvos tão importantes quanto fortalezas."],"narrativeFunction":"Liga territórios distantes e transforma geografia, comércio e logística em instrumentos da guerra.","architecture":"Rota natural com cais, pontes, ilhas fluviais, margens fortificadas e pontos de cobrança construídos por diferentes clãs.","atmosphere":"Água fria no norte, corrente mais larga ao sul, névoa nas quedas e tráfego crescente perto de Kaendar.","resources":["Água","Peixe","Transporte","Ilhas fluviais","Comércio e tributos"],"dangers":["Cheias","Quedas e correntezas","Bloqueios militares","Ataques a barcos","Disputa entre Glydar e Polar"],"culture":["Barqueiros e pescadores","Leis locais de travessia","Conhecimento de cheia","Rotas transmitidas por prática"],"chapterScenes":[{"chapterId":"jesed-chapter-gs-20","relation":"ocorre","text":"A batalha na Margem dos Zírrios disputa cais, pontes e controle do trecho alto do rio.","characterIds":["jesed-character-rendar","jesed-character-ossar-glydar","jesed-character-varael-glydar","jesed-character-lutharus"]},{"chapterId":"jesed-chapter-gs-24","relation":"ocorre","text":"A aliança chega ao Cais dos Zírrios e usa o rio para romper a defesa de Kaendar.","characterIds":["jesed-character-rendar","jesed-character-kaelina-polar","jesed-character-markoso"]},{"chapterId":"jesed-chapter-gs-28","relation":"ocorre","text":"A saída negociada de Rendar passa pelo cais, onde Alyra quebra a palavra de Kaelina e o mata.","characterIds":["jesed-character-rendar","jesed-character-kaelina-polar","jesed-character-alyra-polar"]},{"chapterId":"jesed-chapter-gs-29","relation":"ocorre","text":"Kaelina lança ao rio a peça de Orionus, encerrando simbolicamente a dependência da autoridade do pai.","characterIds":["jesed-character-kaelina-polar","jesed-character-orionus-polar"]}]},"route-garganta-kaendar":{"region":"Leste das terras Polar","location":"Passagem estreita entre elevações que controla a aproximação terrestre a Kaendar.","population":null,"summary":"Passagem defensável que permite aos Polar atrasar exércitos, controlar caravanas e transformar terreno em vantagem.","description":["A Garganta de Kaendar força grupos grandes a reduzir velocidade e formação. Postos de observação e caminhos elevados permitem que poucos defensores controlem a passagem por tempo suficiente para a cidade se preparar.","A defesa funciona enquanto os inimigos aceitam chegar pela rota prevista. O uso do Rio Grande e de alianças internas mostra que nenhuma garganta protege contra todas as formas de guerra."],"narrativeFunction":"Explica a segurança histórica de Kaendar e o método de Orionus, mas também evidencia os limites de confiar numa única defesa.","architecture":"Passagem natural reforçada por postos, barreiras, muros baixos e pontos de lançamento sobre o caminho.","atmosphere":"Pedra, vento canalizado, eco de passos e visibilidade limitada pelas curvas.","resources":["Controle de passagem","Pedágio e vigilância","Defesa natural"],"dangers":["Emboscada","Bloqueio prolongado","Queda de pedras","Falsa sensação de invulnerabilidade"],"culture":["Símbolo da estratégia Polar","Memória da ascensão de Orionus","Patrulha constante"],"chapterScenes":[{"chapterId":"jesed-chapter-gs-02","relation":"recordado","text":"Cal Edran recorda como Orionus usou terreno, espera e logística na Noite da Garganta para vencer sem depender de uma carga frontal.","characterIds":["jesed-character-cal-edran-polar","jesed-character-orionus-polar"]},{"chapterId":"jesed-chapter-gs-24","relation":"citado","text":"A invasão evita depender apenas da garganta e força a abertura do cais, revelando o limite da principal defesa terrestre de Kaendar.","characterIds":["jesed-character-rendar","jesed-character-kaelina-polar"]}]},"route-garganta-seca":{"region":"Entrada das terras Tondrar","location":"Passagem seca e longa entre montanhas antes de Khar-Tondr.","population":null,"summary":"Acesso Tondrar em que distância, sede e espera desgastam visitantes antes de alcançarem a fortaleza.","description":["A Garganta Seca não precisa estar completamente fechada para funcionar como defesa. A falta de água, as curvas e a dificuldade de manter carroças tornam qualquer avanço lento e previsível.","Os Tondrar conhecem poços, sombras e saídas laterais que estrangeiros não percebem. A passagem é parte da identidade do clã porque ensina que sobreviver ao caminho já é uma forma de prova."],"narrativeFunction":"Controla a entrada e saída de Khar-Tondr e permite que marchas, prisioneiros e alianças sejam observados antes de alcançarem a fortaleza.","architecture":"Rota natural entre paredões, com marcas Tondrar, pontos de vigia e acessos laterais discretos.","atmosphere":"Calor, poeira, silêncio e sensação de distância maior do que o mapa sugere.","resources":["Passagem defensável","Poços conhecidos apenas localmente","Pontos de observação"],"dangers":["Sede","Emboscadas","Desmoronamento","Perda de animais e carroças"],"culture":["Prova de resistência","Controle Tondrar da água","Marcas de passagem e memória"],"chapterScenes":[{"chapterId":"jesed-chapter-gs-19","relation":"ocorre","text":"Kaelina é levada prisioneira através da passagem e percebe que cada curva é controlada pelos Tondrar.","characterIds":["jesed-character-kaelina-polar","jesed-character-kharvok","jesed-character-torgun-ossos-de-fome"]},{"chapterId":"jesed-chapter-gs-21","relation":"ocorre","text":"Depois da luta, a comitiva deixa Khar-Tondr pela garganta, com Kaelina ferida e a aliança ainda instável.","characterIds":["jesed-character-kaelina-polar","jesed-character-nynestra-buldar","jesed-character-kharvok"]},{"chapterId":"jesed-chapter-gs-22","relation":"ocorre","text":"Tondrar, Buldar e aliados usam a passagem para iniciar a marcha em direção a Kaendar.","characterIds":["jesed-character-rendar","jesed-character-nynestra-buldar","jesed-character-kharvok","jesed-character-torgun-ossos-de-fome"]}]},"route-estrada-graos":{"region":"Terras Buldar e rotas para o sul","location":"Conjunto de caminhos de terra batida que liga campos, celeiros, Nyn-Harad e territórios consumidores.","population":null,"summary":"Principal rota Buldar de alimento, formada por caminhos repetidos por carroças e não por uma estrada imperial construída.","description":["A Estrada dos Grãos é uma rede de trajetos reconhecidos por marcos, áreas de descanso e costume. Em algumas épocas, vários caminhos paralelos são usados para evitar lama ou campos em colheita.","A rota sustenta Kaendar e outras regiões menos férteis. Por isso, ameaça de bloqueio ou atraso possui efeito político antes mesmo de a fome começar.","Durante a formação da aliança, a mesma infraestrutura que transporta alimento passa a mover combatentes, carroças e informação."],"narrativeFunction":"Demonstra que alimento e tempo de deslocamento são armas tão decisivas quanto lâminas.","architecture":"Caminhos de terra, pequenas pontes, marcos de distância, pátios de descanso e postos de contagem.","atmosphere":"Poeira no período seco, lama nas chuvas, cheiro de grão e filas de carroças.","resources":["Transporte de grãos","Carroças","Animais de carga","Postos de abastecimento"],"dangers":["Bloqueio","Roubo","Incêndio de cargas","Chuva e lama","Ataques a caravanas"],"culture":["Prioridade de passagem para alimento","Contagem de cargas","Acordos entre produtores e transportadores"],"chapterScenes":[{"chapterId":"jesed-chapter-gs-16","relation":"ocorre","text":"A aliança usa as rotas Buldar para reunir provisões e deslocar forças sem interromper completamente o abastecimento das comunidades.","characterIds":["jesed-character-nynestra-buldar","jesed-character-rendar","jesed-character-hadrun"]},{"chapterId":"jesed-chapter-gs-22","relation":"ocorre","text":"Carroças e grupos seguem em tempos diferentes, criando rastros falsos e escondendo o tamanho real da marcha para Kaendar.","characterIds":["jesed-character-rendar","jesed-character-nynestra-buldar","jesed-character-hadrun"]}]},"route-marcha-alianca":{"region":"De Terra Preta e Khar-Tondr até Kaendar","location":"Trajeto militar variável criado durante a campanha, combinando estradas, trilhas, margens e rotas falsas.","population":null,"summary":"Percurso de guerra construído para ocultar o tamanho e a direção da aliança que cerca Kaendar.","description":["A Marcha Oculta não é uma estrada permanente. É o conjunto de escolhas feito por vários clãs para mover combatentes em camadas, separar grupos, produzir rastros falsos e chegar a Kaendar antes que a cidade compreenda o tamanho da ameaça.","A rota muda conforme clima, vigias e abastecimento. Buldar sustentam carroças; Tondrar controlam deslocamentos; grupos menores abrem caminhos e espalham informação contraditória.","O percurso demonstra que uma aliança não se torna um único exército: cada força mantém comando, interesse e limite próprios."],"narrativeFunction":"Converte alianças políticas em pressão física sobre Kaendar e preserva tensões internas até o momento do cerco.","architecture":"Trajeto militar sem construção única, apoiado em estradas existentes, trilhas secundárias, acampamentos temporários e pontos de encontro.","atmosphere":"Marchas noturnas, fogueiras apagadas, ordens contraditórias e longos intervalos de silêncio.","resources":["Provisões Buldar","Guias Tondrar e Fendelar","Carroças","Rastros falsos","Pontos de encontro"],"dangers":["Deserção","Conflito entre aliados","Falta de alimento","Detecção por Vigias Polar","Ataques durante a dispersão"],"culture":["Comandos separados","Acordos temporários","Desconfiança entre clãs","Disciplina baseada em objetivo comum"],"chapterScenes":[{"chapterId":"jesed-chapter-gs-22","relation":"ocorre","text":"A aliança avança em grupos separados, executa um espião Polar e leva Kaelina como refém enquanto Rendar tenta assumir o controle da vingança.","characterIds":["jesed-character-rendar","jesed-character-kaelina-polar","jesed-character-nynestra-buldar","jesed-character-kharvok","jesed-character-torgun-ossos-de-fome","jesed-character-hadrun"]},{"chapterId":"jesed-chapter-gs-23","relation":"ocorre","text":"As forças chegam às proximidades de Kaendar e fecham acessos, obrigando Alyra a recolher o Conselho ao abrigo profundo.","characterIds":["jesed-character-rendar","jesed-character-nynestra-buldar","jesed-character-kharvok","jesed-character-lutharus"]}]}};
  const timeline=C.asArray(D.timeline);
  const unique=values=>[...new Set(C.asArray(values).filter(Boolean))];
  const sourcePlaces=C.asArray(D.places);
  const items=sourcePlaces.map(item=>{
    const id=C.stableId(item.id,'place',item.name,BOOK_ID),spec=specs[id]||{};
    const slug=C.stableSlug(item.slug,item.name);
    const chapterScenes=C.asArray(spec.chapterScenes).map(scene=>({...scene,characterIds:unique(scene.characterIds)}));
    const chapterIds=unique(chapterScenes.map(scene=>scene.chapterId));
    const characterIds=unique(chapterScenes.flatMap(scene=>scene.characterIds));
    const eventIds=timeline.filter(event=>C.asArray(event.placeIds).includes(id)).map(event=>event.id);
    const enriched={...item,...spec,id,slug,name:C.text(item.name),type:C.text(spec.type||item.type||'Lugar'),route:`place/${slug}`,chapterScenes,chapterIds,characterIds,eventIds,population:spec.population||null,sourceRef:item};
    delete enriched.state;
    delete item.state;
    Object.assign(item,enriched);
    return enriched;
  });
  D.places=items;
  D.meta=D.meta||{};D.meta.phase='Etapa 5';
  C.setCollection(BOOK_ID,'places',items);
})();
